```javascript
function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;
  let timerId = null;
  let lastArgs = null;
  let isLeadingInvoked = false;

  function debounced(...args) {
    lastArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    if (leading && !isLeadingInvoked) {
      isLeadingInvoked = true;
      fn.apply(this, lastArgs);
      lastArgs = null;
    }

    timerId = setTimeout(() => {
      if (trailing && lastArgs !== null) {
        fn.apply(this, lastArgs);
      }
      timerId = null;
      lastArgs = null;
      isLeadingInvoked = false;
    }, delay);
  }

  debounced.cancel = function () {
    if (timerId !== null) {
      clearTimeout(timerId);
    }
    timerId = null;
    lastArgs = null;
    isLeadingInvoked = false;
  };

  debounced.flush = function () {
    if (timerId !== null && lastArgs !== null) {
      fn.apply(this, lastArgs);
    }
    debounced.cancel();
  };

  return debounced;
}
```

关键设计：

- **leading / trailing 模式**：`leading: true` 在延时期开始时立即执行第一次调用（比如搜索建议场景），`trailing: true`（默认）在停止触发后执行最后一次调用。
- **this 绑定**：通过 `fn.apply(this, lastArgs)` 保留调用时的上下文，用在事件监听里就不会丢失 DOM 元素引用。
- **`cancel()`**：在组件卸载时清掉未执行的调用，避免内存泄漏。
- **`flush()`**：立即执行排队的最后一次调用并清空定时器，适合表单提交前强制触发校验。

使用示例：

```javascript
// 典型的输入防抖
const handleSearch = debounce(
  (query) => fetchSearchResults(query),
  300
);

// 点击按钮的立即+防抖（比如提交后防重复）
const handleClick = debounce(
  () => submitForm(),
  500,
  { leading: true, trailing: false }
);

// 组件销毁时清理
handleSearch.cancel();
```

